INSERT INTO public.quiz_questions (lesson_id, question, options, correct_answer, explanation) VALUES
  ('30000000-0000-0000-0000-000000000001', 'What is the primary difference between casual AI use and professional prompt engineering?', '["Professional prompt engineering costs more to implement","Professional prompt engineering uses systematic, structured approaches with defined components while casual use relies on natural language requests hoping for good results","Casual AI use is more creative than professional prompt engineering","There is no real difference between the two approaches"]'::jsonb, '1', 'Professional prompt engineering uses systematic, structured approaches with defined components while casual use relies on natural language requests hoping for good results'),
  ('30000000-0000-0000-0000-000000000001', 'Why do most AI failures actually stem from instruction problems rather than AI limitations?', '["AI models are inherently unreliable and buggy","Most AI failures occur because prompts are vague, lack context, have unclear expectations, or contain contradictory requirements","AI models are designed to fail to encourage human oversight","Companies deliberately limit AI capabilities to sell more services"]'::jsonb, '1', 'Most AI failures occur because prompts are vague, lack context, have unclear expectations, or contain contradictory requirements'),
  ('30000000-0000-0000-0000-000000000001', 'Which of the following is NOT a core component of systematic prompt engineering?', '["Defining the role or persona for the AI","Specifying the task with context and requirements","Relying on the AI''s creativity to fill in missing details","Setting explicit constraints and boundaries"]'::jsonb, '2', 'Relying on the AI''s creativity to fill in missing details'),
  ('30000000-0000-0000-0000-000000000001', 'How does treating AI interaction as ''giving instructions'' rather than ''having a conversation'' improve results?', '["It makes AI responses more creative and unpredictable","It eliminates ambiguity by being explicit about requirements, providing clear examples, specifying constraints, and defining success criteria","It allows AI to better understand human emotions and context","It reduces the computational resources needed by the AI"]'::jsonb, '1', 'It eliminates ambiguity by being explicit about requirements, providing clear examples, specifying constraints, and defining success criteria'),
  ('30000000-0000-0000-0000-000000000001', 'What is the main benefit of using systematic prompt engineering in professional settings?', '["It allows for more casual, creative interactions with AI","It ensures consistent, high-quality results that can be relied upon in production environments and scaled across teams","It makes AI responses faster and more efficient","It reduces the cost of using AI systems"]'::jsonb, '1', 'It ensures consistent, high-quality results that can be relied upon in production environments and scaled across teams'),
  ('30000000-0000-0000-0000-000000000002', 'How do AI models primarily process text instructions?', '["AI models process text the same way humans do, with context and understanding","AI models process text as sequences of tokens using statistical patterns to predict the next most likely tokens","AI models use a complex algorithm that mimics human thought processes","AI models analyze text based on semantic meaning and emotional context"]'::jsonb, '1', 'AI models process text as sequences of tokens using statistical patterns to predict the next most likely tokens'),
  ('30000000-0000-0000-0000-000000000002', 'Why is understanding context windows important in prompt engineering?', '["Context windows determine how much information the AI can process, and information at the beginning and end may be weighted differently","Context windows only affect the speed of AI processing","Context windows are marketing terms with no practical impact","Context windows only matter for very long documents"]'::jsonb, '0', 'Context windows determine how much information the AI can process, and information at the beginning and end may be weighted differently'),
  ('30000000-0000-0000-0000-000000000002', 'What is the main difference between how humans and AI models interpret instructions?', '["Humans use context, tone, and shared understanding, while AI models recognize patterns and respond to explicit instructions","Humans are more creative than AI models when interpreting instructions","AI models are better at understanding complex instructions than humans","There is no significant difference in how humans and AI interpret instructions"]'::jsonb, '0', 'Humans use context, tone, and shared understanding, while AI models recognize patterns and respond to explicit instructions'),
  ('30000000-0000-0000-0000-000000000002', 'Why are examples particularly effective in prompts?', '["Examples show the AI exactly what pattern to follow, which is often more effective than abstract instructions","Examples make prompts longer and more impressive to human readers","Examples are only useful for creative tasks, not technical ones","Examples are required by AI model licensing agreements"]'::jsonb, '0', 'Examples show the AI exactly what pattern to follow, which is often more effective than abstract instructions'),
  ('30000000-0000-0000-0000-000000000002', 'How does the ordering of information in a prompt affect AI interpretation?', '["Information at the beginning and end of prompts often gets more weight in the AI''s processing","Ordering only matters for creative writing, not technical tasks","AI models process all information in a prompt equally regardless of order","Ordering affects only the speed of AI response, not the content"]'::jsonb, '0', 'Information at the beginning and end of prompts often gets more weight in the AI''s processing'),
  ('30000000-0000-0000-0000-000000000003', 'What is the main difference between delegating to humans versus AI systems?', '["There is no significant difference between delegating to humans versus AI","Humans can rely on shared context and common sense while AI needs explicit instructions with no gaps in logic or missing context","AI systems are more creative and flexible than humans","Humans require more detailed instructions than AI systems"]'::jsonb, '1', 'Humans can rely on shared context and common sense while AI needs explicit instructions with no gaps in logic or missing context'),
  ('30000000-0000-0000-0000-000000000003', 'Why do AI systems need explicit boundaries in prompts?', '["AI systems respond to patterns and may extrapolate beyond intended boundaries without explicit constraints","Explicit boundaries make the prompt longer and more impressive","AI systems only follow boundaries when they are explicitly told to","Explicit boundaries are required by AI model licensing agreements"]'::jsonb, '0', 'AI systems respond to patterns and may extrapolate beyond intended boundaries without explicit constraints'),
  ('30000000-0000-0000-0000-000000000003', 'What does it mean that AI lacks ''common sense''?', '["AI systems process text based on learned patterns without the ability to fill in gaps with general world knowledge or apply practical judgment","AI systems are intentionally designed to ignore common sense","AI systems have better common sense than humans","Common sense is not relevant for AI systems"]'::jsonb, '0', 'AI systems process text based on learned patterns without the ability to fill in gaps with general world knowledge or apply practical judgment'),
  ('30000000-0000-0000-0000-000000000003', 'How does AI creativity differ from human creativity?', '["AI excels at following patterns with specific parameters while humans can think outside the box in novel ways","AI creativity is superior to human creativity in all contexts","Human creativity is just pattern matching like AI","AI and human creativity work exactly the same way"]'::jsonb, '0', 'AI excels at following patterns with specific parameters while humans can think outside the box in novel ways'),
  ('30000000-0000-0000-0000-000000000003', 'Why is it important to provide explicit examples in AI prompts?', '["AI systems need examples to understand the exact patterns they should follow, as they cannot infer patterns from abstract descriptions alone","Examples make prompts look more professional to human reviewers","AI systems are required by design to follow examples exactly","Examples are only useful for creative tasks, not technical ones"]'::jsonb, '0', 'AI systems need examples to understand the exact patterns they should follow, as they cannot infer patterns from abstract descriptions alone'),
  ('30000000-0000-0000-0000-000000000004', 'What is the primary purpose of the role definition component in a prompt?', '["To make the prompt longer and more impressive","To establish who the AI should act as when completing the task, providing expertise and perspective","To show off your knowledge of AI systems","To slow down the AI''s processing time"]'::jsonb, '1', 'To establish who the AI should act as when completing the task, providing expertise and perspective'),
  ('30000000-0000-0000-0000-000000000004', 'Which component of a structured prompt specifies what the AI should NOT do?', '["Task Definition component","Constraints and Boundaries component","Role Definition component","Output Format component"]'::jsonb, '1', 'Constraints and Boundaries component'),
  ('30000000-0000-0000-0000-000000000004', 'Why are output format specifications important in professional settings?', '["They make the prompt look more professional","They ensure consistency and make outputs suitable for integration with other systems","They slow down the AI''s response time","They are required by AI model licensing agreements"]'::jsonb, '1', 'They ensure consistency and make outputs suitable for integration with other systems'),
  ('30000000-0000-0000-0000-000000000004', 'How does a well-defined task definition improve prompt effectiveness?', '["It clearly specifies what the AI should do with specific requirements and expectations","It makes the prompt more creative and interesting","It reduces the computational resources needed","It forces the AI to respond in a specific language"]'::jsonb, '0', 'It clearly specifies what the AI should do with specific requirements and expectations'),
  ('30000000-0000-0000-0000-000000000004', 'What happens when you rely on the AI to infer missing prompt components?', '["The AI automatically fills in missing context like a human would","The results become inconsistent and unpredictable because AI cannot fill in missing context like humans","The AI produces better results because it has more freedom","Nothing happens; AI doesn''t need complete prompts"]'::jsonb, '1', 'The results become inconsistent and unpredictable because AI cannot fill in missing context like humans'),
  ('30000000-0000-0000-0000-000000000005', 'What is the difference between global and local context in prompt engineering?', '["There is no difference between global and local context","Global context includes broad, general instructions; local context includes task-specific details","Global context is more important than local context","Local context is used only for creative tasks"]'::jsonb, '1', 'Global context includes broad, general instructions; local context includes task-specific details'),
  ('30000000-0000-0000-0000-000000000005', 'Why does context dumping reduce prompt effectiveness?', '["It makes the prompt look more professional","It overwhelms the AI''s processing capacity and dilutes important instructions with excessive information","AI models prefer longer prompts with more context","Context dumping is required for complex tasks"]'::jsonb, '1', 'It overwhelms the AI''s processing capacity and dilutes important instructions with excessive information'),
  ('30000000-0000-0000-0000-000000000005', 'How does the position of information in a prompt affect AI processing?', '["Position has no impact on AI processing","Information at the beginning and end often receives more attention than information in the middle","Middle information is always processed most carefully","AI processes all information in a prompt equally regardless of position"]'::jsonb, '1', 'Information at the beginning and end often receives more attention than information in the middle'),
  ('30000000-0000-0000-0000-000000000005', 'What are persistent instructions in the context of prompt engineering?', '["Instructions that apply only to a single interaction","Instructions that should apply across multiple interactions or remain in effect for extended periods","Instructions that are only used for creative tasks","Instructions that are temporary and change frequently"]'::jsonb, '1', 'Instructions that should apply across multiple interactions or remain in effect for extended periods'),
  ('30000000-0000-0000-0000-000000000005', 'What happens when you don''t properly layer context in a prompt?', '["The AI processes all information more carefully","Critical instructions may be ignored or diluted, leading to inconsistent or irrelevant results","The results become more creative and innovative","Nothing negative happens; AI handles context automatically"]'::jsonb, '1', 'Critical instructions may be ignored or diluted, leading to inconsistent or irrelevant results'),
  ('30000000-0000-0000-0000-000000000006', 'What is the primary purpose of constraints in prompt engineering?', '["To make prompts longer and more impressive","To define boundaries and prevent unwanted behaviors while maintaining AI effectiveness","To slow down AI processing time","To show off your knowledge of AI systems"]'::jsonb, '1', 'To define boundaries and prevent unwanted behaviors while maintaining AI effectiveness'),
  ('30000000-0000-0000-0000-000000000006', 'How do format constraints improve professional AI interactions?', '["They make the prompt look more professional","They ensure outputs follow specific structures required for integration and consistency","They force the AI to use specific words","They are required by AI model licensing agreements"]'::jsonb, '1', 'They ensure outputs follow specific structures required for integration and consistency'),
  ('30000000-0000-0000-0000-000000000006', 'Why is it important to specify what NOT to do in constraints?', '["It''s not important to specify what NOT to do","Negative constraints prevent inappropriate content and off-topic responses","Positive constraints are always more effective than negative ones","AI systems automatically know what not to do"]'::jsonb, '1', 'Negative constraints prevent inappropriate content and off-topic responses'),
  ('30000000-0000-0000-0000-000000000006', 'What are AI hallucinations in the context of prompt engineering?', '["When the AI refuses to respond to any prompts","When the AI generates information that sounds plausible but is factually incorrect","When the AI responds too slowly to prompts","When the AI uses too many technical terms"]'::jsonb, '1', 'When the AI generates information that sounds plausible but is factually incorrect'),
  ('30000000-0000-0000-0000-000000000006', 'How do scope constraints improve AI output quality?', '["They make the AI respond more slowly","They prevent responses from becoming too broad, too narrow, or off-topic","They force the AI to use specific formatting","They are only important for creative tasks"]'::jsonb, '1', 'They prevent responses from becoming too broad, too narrow, or off-topic'),
  ('30000000-0000-0000-0000-000000000007', 'What is the main purpose of few-shot learning in prompts?', '["To make the AI respond faster","To provide examples that demonstrate the desired format or approach","To reduce the cost of using AI","To make the AI more creative"]'::jsonb, '1', 'To provide examples that demonstrate the desired format or approach'),
  ('30000000-0000-0000-0000-000000000007', 'How does the quality of examples in few-shot prompting affect AI performance?', '["The quality of examples has minimal impact on performance","The quality and clarity of examples directly impact the AI''s performance","Only the quantity of examples matters, not quality","AI models ignore example quality"]'::jsonb, '1', 'The quality and clarity of examples directly impact the AI''s performance'),
  ('30000000-0000-0000-0000-000000000007', 'Which of the following is NOT a key consideration for effective few-shot learning?', '["Using clear, relevant examples","Maintaining consistent formatting","Using as many examples as possible to ensure comprehensive coverage","Providing representative examples"]'::jsonb, '2', 'Using as many examples as possible to ensure comprehensive coverage'),
  ('30000000-0000-0000-0000-000000000007', 'What is the relationship between the number of examples provided and the quality of AI responses in few-shot learning?', '["More examples always lead to decreased performance","More examples generally lead to more consistent and accurate responses","The number of examples has no impact on quality","Fewer examples always produce better results"]'::jsonb, '1', 'More examples generally lead to more consistent and accurate responses'),
  ('30000000-0000-0000-0000-000000000007', 'How does few-shot learning differ from zero-shot learning in terms of example provision?', '["Few-shot learning provides examples in the prompt, while zero-shot learning does not provide any examples","Few-shot learning uses more computational resources","Zero-shot learning requires examples","There is no difference between the two approaches"]'::jsonb, '0', 'Few-shot learning provides examples in the prompt, while zero-shot learning does not provide any examples'),
  ('30000000-0000-0000-0000-000000000008', 'What is the primary benefit of prompt chaining?', '["It makes the AI respond faster","It allows complex tasks to be broken into specialized steps","It reduces the cost of using AI","It makes the AI more creative"]'::jsonb, '1', 'It allows complex tasks to be broken into specialized steps'),
  ('30000000-0000-0000-0000-000000000008', 'How does the iterative refinement process improve prompt effectiveness?', '["By testing, analyzing output, identifying issues, and adjusting prompts based on results","By making random changes to the prompt","By increasing the length of the prompt","By using more complex vocabulary"]'::jsonb, '0', 'By testing, analyzing output, identifying issues, and adjusting prompts based on results'),
  ('30000000-0000-0000-0000-000000000008', 'Which of the following is NOT a key component of systematic prompt testing?', '["Testing prompts with different inputs","Validating results across various scenarios","Using only one test input to validate the prompt","Identifying edge cases"]'::jsonb, '2', 'Using only one test input to validate the prompt'),
  ('30000000-0000-0000-0000-000000000008', 'What is the relationship between prompt complexity and the need for iterative refinement?', '["Simple prompts always require more iterations than complex ones","More complex prompts typically require more iterations to achieve desired results","Complexity has no impact on the number of iterations needed","Simple prompts are impossible to refine"]'::jsonb, '1', 'More complex prompts typically require more iterations to achieve desired results'),
  ('30000000-0000-0000-0000-000000000008', 'How does prompt chaining differ from using a single complex prompt for multi-step tasks?', '["Chaining allows specialized processing at each step, often producing higher quality results","Single prompts are always more efficient","There is no practical difference between the approaches","Single prompts allow for better resource management"]'::jsonb, '0', 'Chaining allows specialized processing at each step, often producing higher quality results'),
  ('30000000-0000-0000-0000-000000000009', 'What is the primary purpose of controlling creativity in AI responses?', '["To make the AI respond faster","To match the response style to the requirements of the specific task","To reduce the cost of using AI","To make the AI more creative in all cases"]'::jsonb, '1', 'To match the response style to the requirements of the specific task'),
  ('30000000-0000-0000-0000-000000000009', 'How does temperature setting affect the randomness of AI responses?', '["Temperature has no effect on randomness","Lower temperatures produce more predictable responses, higher temperatures produce more creative responses","Higher temperatures make responses more predictable","Temperature only affects response speed"]'::jsonb, '1', 'Lower temperatures produce more predictable responses, higher temperatures produce more creative responses'),
  ('30000000-0000-0000-0000-000000000009', 'Which of the following is NOT a method for controlling creativity in AI responses?', '["Using temperature settings","Using specific language in prompts","Changing the font size in the prompt","Adjusting system parameters"]'::jsonb, '2', 'Changing the font size in the prompt'),
  ('30000000-0000-0000-0000-000000000009', 'What is the relationship between task type and appropriate creativity level?', '["All tasks require the same level of creativity","Technical tasks need low creativity for accuracy, creative tasks benefit from high creativity","Creative tasks should always use low creativity","Creativity level doesn''t affect task outcomes"]'::jsonb, '1', 'Technical tasks need low creativity for accuracy, creative tasks benefit from high creativity'),
  ('30000000-0000-0000-0000-000000000009', 'How do prompt techniques influence AI creativity compared to temperature settings?', '["Prompt techniques use language to guide behavior while temperature controls randomness","Prompt techniques are more effective than temperature settings","Temperature settings are more effective than prompt techniques","There is no difference between the two approaches"]'::jsonb, '0', 'Prompt techniques use language to guide behavior while temperature controls randomness'),
  ('30000000-0000-0000-0000-000000000010', 'What is zero-shot prompting?', '["Prompting without providing examples","Prompting with many examples","Prompting that makes the AI respond quickly","Prompting that reduces AI creativity"]'::jsonb, '0', 'Prompting without providing examples'),
  ('30000000-0000-0000-0000-000000000010', 'How does self-consistency technique improve AI response accuracy?', '["By using more computational resources","By generating multiple responses and selecting the most consistent answer","By reducing response length","By limiting the AI''s vocabulary"]'::jsonb, '1', 'By generating multiple responses and selecting the most consistent answer'),
  ('30000000-0000-0000-0000-000000000010', 'Which of the following is NOT a requirement for effective zero-shot prompting?', '["Clear instructions","Sufficient context","Providing multiple examples for reference","Well-defined output format"]'::jsonb, '2', 'Providing multiple examples for reference'),
  ('30000000-0000-0000-0000-000000000010', 'What is the relationship between instruction clarity and zero-shot prompting success?', '["Clarity has no impact on success","Clear, comprehensive instructions are crucial for success","Complex instructions work better than clear ones","Instruction clarity only matters for creative tasks"]'::jsonb, '1', 'Clear, comprehensive instructions are crucial for success'),
  ('30000000-0000-0000-0000-000000000010', 'How do zero-shot and few-shot prompting differ in their approach to examples?', '["Zero-shot uses no examples while few-shot provides examples","Zero-shot is always more effective than few-shot","There is no practical difference between the two","Few-shot uses no examples while zero-shot provides examples"]'::jsonb, '0', 'Zero-shot uses no examples while few-shot provides examples'),
  ('30000000-0000-0000-0000-000000000011', 'Why is it important to specify the target audience in content creation prompts?', '["It makes the AI respond faster","It helps the AI create content that resonates with the intended audience","It reduces the cost of using AI","It makes the AI more creative"]'::jsonb, '1', 'It helps the AI create content that resonates with the intended audience'),
  ('30000000-0000-0000-0000-000000000011', 'How does platform-specific prompting improve content effectiveness?', '["By making the AI respond faster","By tailoring content to platform-specific requirements and audience expectations","By reducing the cost of content creation","By making the content more creative"]'::jsonb, '1', 'By tailoring content to platform-specific requirements and audience expectations'),
  ('30000000-0000-0000-0000-000000000011', 'Which of the following is NOT a core concept in content creation prompt engineering?', '["Platform-specific content approaches","Audience segmentation techniques","Using generic language for all platforms","Content format specifications"]'::jsonb, '2', 'Using generic language for all platforms'),
  ('30000000-0000-0000-0000-000000000011', 'What is the relationship between content format specification and output quality?', '["Format specification has no impact on output quality","Specifying format requirements leads to better structured and more relevant content","Generic formats produce higher quality content","Format requirements limit creativity"]'::jsonb, '1', 'Specifying format requirements leads to better structured and more relevant content'),
  ('30000000-0000-0000-0000-000000000011', 'How do detailed prompts compare to generic prompts in content creation?', '["Detailed prompts produce more relevant and targeted content than generic prompts","Generic prompts are always more effective","Detailed prompts reduce content quality","There is no difference between detailed and generic prompts"]'::jsonb, '0', 'Detailed prompts produce more relevant and targeted content than generic prompts'),
  ('30000000-0000-0000-0000-000000000012', 'What is the primary benefit of specifying programming language in code generation prompts?', '["It makes the AI respond faster","It ensures the AI generates code in the correct syntax and style","It reduces the cost of using AI","It makes the AI more creative"]'::jsonb, '1', 'It ensures the AI generates code in the correct syntax and style'),
  ('30000000-0000-0000-0000-000000000012', 'How do clear functionality requirements improve code generation quality?', '["By making the AI respond faster","By providing clear specifications of what the code should do, including inputs, outputs, and constraints","By reducing the complexity of the code","By making the code shorter"]'::jsonb, '1', 'By providing clear specifications of what the code should do, including inputs, outputs, and constraints'),
  ('30000000-0000-0000-0000-000000000012', 'Which of the following is NOT a core concept in code generation prompt engineering?', '["Language-specific prompts","Functionality requirements","Avoiding specific language requirements","Code quality considerations"]'::jsonb, '2', 'Avoiding specific language requirements'),
  ('30000000-0000-0000-0000-000000000012', 'What is the relationship between code quality requirements and generated code quality?', '["Quality requirements have no impact on generated code","Specifying quality requirements helps generate code that follows best practices","Quality requirements reduce code performance","Quality requirements make code less readable"]'::jsonb, '1', 'Specifying quality requirements helps generate code that follows best practices'),
  ('30000000-0000-0000-0000-000000000012', 'How do detailed coding prompts compare to generic coding prompts?', '["Detailed prompts produce more accurate and appropriate code than generic prompts","Generic prompts are always more effective","Detailed prompts reduce code quality","There is no difference between detailed and generic prompts"]'::jsonb, '0', 'Detailed prompts produce more accurate and appropriate code than generic prompts'),
  ('30000000-0000-0000-0000-000000000013', 'Why is it important to provide context about a dataset in analysis prompts?', '["It makes the AI respond faster","It helps the AI understand the significance and provide relevant insights","It reduces the cost of using AI","It makes the AI more creative"]'::jsonb, '1', 'It helps the AI understand the significance and provide relevant insights'),
  ('30000000-0000-0000-0000-000000000013', 'How do clear analysis objectives improve the quality of AI-generated insights?', '["By making the AI respond faster","By guiding the AI to focus on the most relevant aspects of the data","By reducing the amount of data to process","By making the analysis simpler"]'::jsonb, '1', 'By guiding the AI to focus on the most relevant aspects of the data'),
  ('30000000-0000-0000-0000-000000000013', 'Which of the following is NOT a core concept in data analysis prompt engineering?', '["Data context setting","Analysis objectives","Avoiding specific objectives","Output requirements"]'::jsonb, '2', 'Avoiding specific objectives'),
  ('30000000-0000-0000-0000-000000000013', 'What is the relationship between output specifications and analysis usability?', '["Output specifications have no impact on usability","Specifying output format ensures results are in a usable format for the user","Output specifications reduce analysis quality","Specifying format makes results less relevant"]'::jsonb, '1', 'Specifying output format ensures results are in a usable format for the user'),
  ('30000000-0000-0000-0000-000000000013', 'How do structured prompts compare to general prompts in data analysis?', '["Structured prompts produce more relevant and actionable insights than general prompts","General prompts are always more effective","Structured prompts reduce analysis quality","There is no difference between structured and general prompts"]'::jsonb, '0', 'Structured prompts produce more relevant and actionable insights than general prompts'),
  ('30000000-0000-0000-0000-000000000014', 'What is a common mistake in prompt engineering?', '["Providing too much context","Using ambiguous or unclear language","Being too specific","Using simple language"]'::jsonb, '1', 'Using ambiguous or unclear language'),
  ('30000000-0000-0000-0000-000000000014', 'How does ambiguous language affect AI response quality?', '["It has no effect on responses","It leads to varied interpretations and inconsistent results","It makes responses more consistent","It speeds up response time"]'::jsonb, '1', 'It leads to varied interpretations and inconsistent results'),
  ('30000000-0000-0000-0000-000000000014', 'Which of the following is NOT a common prompt engineering mistake?', '["Using ambiguous language","Missing context","Providing sufficient context","Overly complex prompts"]'::jsonb, '2', 'Providing sufficient context'),
  ('30000000-0000-0000-0000-000000000014', 'What is the relationship between prompt complexity and response quality?', '["Simple prompts always produce better results","Overly complex prompts can confuse the AI and reduce response quality","Complexity has no impact on quality","More complex prompts always produce better results"]'::jsonb, '1', 'Overly complex prompts can confuse the AI and reduce response quality'),
  ('30000000-0000-0000-0000-000000000014', 'How do best practices in prompt engineering improve results?', '["By helping avoid common pitfalls and creating more effective prompts","By making prompts more complex","By reducing the need for testing","By making responses less accurate"]'::jsonb, '0', 'By helping avoid common pitfalls and creating more effective prompts'),
  ('30000000-0000-0000-0000-000000000015', 'Why is testing important in prompt engineering?', '["It makes the AI respond faster","It ensures prompts work reliably across different inputs and scenarios","It reduces the cost of using AI","It makes the AI more creative"]'::jsonb, '1', 'It ensures prompts work reliably across different inputs and scenarios'),
  ('30000000-0000-0000-0000-000000000015', 'How does edge case testing improve prompt reliability?', '["By making prompts respond faster","By identifying potential failures with unusual or extreme inputs","By reducing the complexity of prompts","By making prompts more creative"]'::jsonb, '1', 'By identifying potential failures with unusual or extreme inputs'),
  ('30000000-0000-0000-0000-000000000015', 'Which of the following is NOT a core component of prompt validation?', '["Edge case testing","Consistency validation","Avoiding edge case testing","Performance testing"]'::jsonb, '2', 'Avoiding edge case testing'),
  ('30000000-0000-0000-0000-000000000015', 'What is the relationship between consistency validation and reliable prompt performance?', '["There is no relationship between them","Consistency validation ensures prompts produce reproducible outputs","Consistency validation reduces performance","Reliable performance eliminates the need for consistency validation"]'::jsonb, '1', 'Consistency validation ensures prompts produce reproducible outputs'),
  ('30000000-0000-0000-0000-000000000015', 'How do systematic testing approaches compare to ad-hoc testing?', '["Systematic testing is more thorough and reliable than ad-hoc testing","Ad-hoc testing is always more effective","There is no difference between the approaches","Systematic testing is less effective than ad-hoc testing"]'::jsonb, '0', 'Systematic testing is more thorough and reliable than ad-hoc testing'),
  ('30000000-0000-0000-0000-000000000016', 'What is the main benefit of combining multiple prompt engineering techniques?', '["It makes the AI respond faster","It allows for solving complex challenges that require multiple approaches","It reduces the cost of using AI","It makes the AI more creative in all cases"]'::jsonb, '1', 'It allows for solving complex challenges that require multiple approaches'),
  ('30000000-0000-0000-0000-000000000016', 'How does technique synthesis improve the ability to solve complex challenges?', '["By making the AI respond faster","By allowing different approaches to be applied to different aspects of the task","By reducing the complexity of each prompt","By making the AI more creative"]'::jsonb, '1', 'By allowing different approaches to be applied to different aspects of the task'),
  ('30000000-0000-0000-0000-000000000016', 'Which of the following is NOT a core concept in advanced prompt engineering projects?', '["Technique synthesis","Complex task decomposition","Avoiding iterative refinement","Iterative development"]'::jsonb, '2', 'Avoiding iterative refinement'),
  ('30000000-0000-0000-0000-000000000016', 'What is the relationship between iterative development and prompt improvement?', '["There is no relationship between them","Iterative development leads to increasingly sophisticated and effective prompts","Iterative development reduces prompt effectiveness","Iterative development eliminates the need for testing"]'::jsonb, '1', 'Iterative development leads to increasingly sophisticated and effective prompts'),
  ('30000000-0000-0000-0000-000000000016', 'How does breaking down complex tasks help in prompt engineering?', '["It makes the task more complex","It allows for specialized prompts to address each component effectively","It reduces the effectiveness of prompts","It eliminates the need for testing"]'::jsonb, '1', 'It allows for specialized prompts to address each component effectively'),
  ('20000000-0000-0000-0000-000000000001', 'What type of system does Facebook Ads operate on?', '["An auction system where ads compete for audience attention","A direct purchase system where you buy specific impressions","A lottery system where placement is random","A subscription system where you pay for guaranteed placement"]'::jsonb, '0', 'An auction system where ads compete for audience attention'),
  ('20000000-0000-0000-0000-000000000001', 'What three factors does Facebook''s auction consider?', '["Bid amount, ad relevance, and estimated action rate","Daily budget, audience size, and ad spend","Creative type, targeting options, and campaign objective","Click-through rate, conversion rate, and cost per click"]'::jsonb, '0', 'Bid amount, ad relevance, and estimated action rate'),
  ('20000000-0000-0000-0000-000000000001', 'Why is understanding Facebook''s revenue model important?', '["It helps align your campaigns with Facebook''s incentives","It allows you to trick the algorithm","It reduces your ad spend requirements","It guarantees ad approval"]'::jsonb, '0', 'It helps align your campaigns with Facebook''s incentives'),
  ('20000000-0000-0000-0000-000000000001', 'What happens when your ad doesn''t provide value to users?', '["Your campaign may be rejected or limited by the algorithm","Your ads will show more frequently","Your cost per click will decrease","Your audience targeting will expand"]'::jsonb, '0', 'Your campaign may be rejected or limited by the algorithm'),
  ('20000000-0000-0000-0000-000000000001', 'How should you approach campaign planning after understanding the auction system?', '["Consider how your campaign provides value to users and Facebook''s revenue goals","Focus only on your own business objectives","Ignore Facebook''s requirements and optimize only for conversions","Bid as high as possible to guarantee placement"]'::jsonb, '0', 'Consider how your campaign provides value to users and Facebook''s revenue goals'),
  ('20000000-0000-0000-0000-000000000002', 'What is the central hub of the Facebook Ads ecosystem?', '["Business Manager","Ad Account","Facebook Page","Instagram Account"]'::jsonb, '0', 'Business Manager'),
  ('20000000-0000-0000-0000-000000000002', 'What are the three main components of the ecosystem?', '["Business Manager, Ad Accounts, and Facebook Pages","Ad Account, Campaign, Ad Set","Page, Post, Ad","Audience, Creative, Bid"]'::jsonb, '0', 'Business Manager, Ad Accounts, and Facebook Pages'),
  ('20000000-0000-0000-0000-000000000002', 'Why is Business Manager important for account safety?', '["It controls access, permissions, and relationships","It increases your ad spend","It guarantees ad approval","It reduces your cost per click"]'::jsonb, '0', 'It controls access, permissions, and relationships'),
